from fastapi import FastAPI, Depends, HTTPException, status
from fastapi.security import HTTPBearer, HTTPAuthorizationCredentials
from pydantic import BaseModel
from typing import List
from datetime import date

app = FastAPI()

security = HTTPBearer()


class Employee(BaseModel):
    id: int
    name: str
    department: str
    position: str
    salary: float
    hire_date: date


EMPLOYEES_DB = [
    Employee(id=1, name="Alice Johnson", department="Engineering", position="Senior Engineer", salary=95000.00, hire_date=date(2020, 3, 15)),
    Employee(id=2, name="Bob Smith", department="Marketing", position="Marketing Specialist", salary=65000.00, hire_date=date(2021, 7, 1)),
    Employee(id=3, name="Carol White", department="Engineering", position="Junior Engineer", salary=72000.00, hire_date=date(2022, 1, 10)),
    Employee(id=4, name="David Brown", department="HR", position="HR Coordinator", salary=58000.00, hire_date=date(2019, 11, 20)),
    Employee(id=5, name="Eva Martinez", department="Finance", position="Financial Analyst", salary=80000.00, hire_date=date(2021, 4, 5)),
]


def verify_token(token: str) -> dict:
    if token == "valid_manager_token":
        return {"sub": "manager_user", "role": "manager"}
    elif token == "valid_employee_token":
        return {"sub": "regular_user", "role": "employee"}
    else:
        raise HTTPException(
            status_code=status.HTTP_401_UNAUTHORIZED,
            detail="Invalid or expired token",
            headers={"WWW-Authenticate": "Bearer"},
        )


def require_role(role: str):
    def role_checker(credentials: HTTPAuthorizationCredentials = Depends(security)) -> dict:
        token = credentials.credentials
        payload = verify_token(token)
        if payload.get("role") != role:
            raise HTTPException(
                status_code=status.HTTP_403_FORBIDDEN,
                detail=f"Access denied: '{role}' role required",
            )
        return payload
    return role_checker


@app.get("/employees", response_model=List[Employee])
def get_employees(
    current_user: dict = Depends(require_role("manager"))
) -> List[Employee]:
    return EMPLOYEES_DB
