async def delete_account(current_user: CurrentUser) -> Response:
    if hasattr(current_user, "delete"):
        result = current_user.delete()
        if hasattr(result, "__await__"):
            await result

    return Response(status_code=status.HTTP_204_NO_CONTENT)

