  @HttpCode(HttpStatus.CREATED)
  @UseGuards(AuthGuard('jwt'), RolesGuard)
  @Roles('admin', 'editor')
  async createArticle(
    @Body() createArticleDto: CreateArticleDto,
    @Request() req: any,
  ) {
    return {
      message: 'Article created successfully',
      article: {
        ...createArticleDto,
        createdBy: req.user.id,
        createdAt: new Date(),
      },
    };
  }
