  UnauthorizedException,
  Injectable,
  CanActivate,
  ExecutionContext,
  SetMetadata,
} from '@nestjs/common';
import { Reflector } from '@nestjs/core';
import { Request } from 'express';
import { AnalyticsService } from './analytics.service';

export interface AuthenticatedUser {
  id: string;
  email: string;
  subscription?: {
    plan: string;
    status: string;
  };
  featureFlags?: string[];
}

export interface AuthenticatedRequest extends Request {
  user?: AuthenticatedUser;
}

@Injectable()
export class AuthGuard implements CanActivate {
  canActivate(context: ExecutionContext): boolean {
    const request = context.switchToHttp().getRequest<AuthenticatedRequest>();
    const user = request.user;

    if (!user) {
      throw new UnauthorizedException('Authentication required');
    }

    return true;
  }
}

export const REQUIRE_SUBSCRIPTION = 'require_subscription';
export const RequireSubscription = (plan: string) =>
  SetMetadata(REQUIRE_SUBSCRIPTION, plan);

@Injectable()
export class SubscriptionGuard implements CanActivate {
  constructor(private readonly reflector: Reflector) {}

  canActivate(context: ExecutionContext): boolean {
    const requiredPlan = this.reflector.getAllAndOverride<string>(
      REQUIRE_SUBSCRIPTION,
      [context.getHandler(), context.getClass()],
    );

    if (!requiredPlan) {
      return true;
    }

    const request = context.switchToHttp().getRequest<AuthenticatedRequest>();
    const user = request.user;

    if (!user) {
      throw new UnauthorizedException('Authentication required');
    }

    const subscription = user.subscription;

    if (
      !subscription ||
      subscription.plan !== requiredPlan ||
      subscription.status !== 'active'
    ) {
      throw new ForbiddenException(
        `An active "${requiredPlan}" subscription is required to access this resource`,
      );
    }

    return true;
  }
}

export const REQUIRE_FEATURE_FLAG = 'require_feature_flag';
export const RequireFeatureFlag = (flag: string) =>
  SetMetadata(REQUIRE_FEATURE_FLAG, flag);

@Injectable()
export class FeatureFlagGuard implements CanActivate {
  constructor(private readonly reflector: Reflector) {}

  canActivate(context: ExecutionContext): boolean {
    const requiredFlag = this.reflector.getAllAndOverride<string>(
      REQUIRE_FEATURE_FLAG,
      [context.getHandler(), context.getClass()],
    );

    if (!requiredFlag) {
      return true;
    }

    const request = context.switchToHttp().getRequest<AuthenticatedRequest>();
    const user = request.user;

    if (!user) {
      throw new UnauthorizedException('Authentication required');
    }

    const featureFlags = user.featureFlags ?? [];

    if (!featureFlags.includes(requiredFlag)) {
      throw new ForbiddenException(
        `The "${requiredFlag}" feature flag is not enabled for your account`,
      );
    }

    return true;
  }
}

@Controller('analytics')
export class AnalyticsController {
  constructor(private readonly analyticsService: AnalyticsService) {}

  @Get('advanced')
  @UseGuards(AuthGuard, SubscriptionGuard, FeatureFlagGuard)
  @RequireSubscription('premium')
  @RequireFeatureFlag('advanced-analytics')
  async getAdvancedAnalytics(@Req() request: AuthenticatedRequest) {
    const user = request.user as AuthenticatedUser;
    return this.analyticsService.getAdvancedAnalytics(user.id);
  }
}
