const SUBSCRIPTION_REPOSITORY = 'SUBSCRIPTION_REPOSITORY';
const FEATURE_FLAG_REPOSITORY = 'FEATURE_FLAG_REPOSITORY';

// ─── Premium Subscription Guard ──────────────────────────────────────────────

@Injectable()
class PremiumSubscriptionGuard implements CanActivate {
  constructor(
    @InjectRepository(Subscription)
    private readonly subscriptionRepository: Repository<Subscription>,
  ) {}

  async canActivate(context: ExecutionContext): Promise<boolean> {
    const request = context.switchToHttp().getRequest();
    const user: User = request.user;

    if (!user) {
      return false;
    }

    const subscription = await this.subscriptionRepository.findOne({
      where: { userId: user.id },
    });

    if (!subscription) {
      throw new ForbiddenException(
        'An active premium subscription is required to access this resource.',
      );
    }

    const isPremiumAndActive =
      subscription.plan === 'premium' && subscription.status === 'active';

    if (!isPremiumAndActive) {
      throw new ForbiddenException(
        'An active premium subscription is required to access this resource.',
      );
    }

    return true;
  }
}

// ─── Feature Flag Guard ──────────────────────────────────────────────────────

const FEATURE_FLAG_KEY = 'featureFlag';

const RequireFeatureFlag = (flagName: string) =>
  SetMetadata(FEATURE_FLAG_KEY, flagName);

@Injectable()
class FeatureFlagGuard implements CanActivate {
  constructor(
    private readonly reflector: Reflector,
    @InjectRepository(FeatureFlag)
    private readonly featureFlagRepository: Repository<FeatureFlag>,
  ) {}

  async canActivate(context: ExecutionContext): Promise<boolean> {
    const requiredFlag = this.reflector.getAllAndOverride<string>(
      FEATURE_FLAG_KEY,
      [context.getHandler(), context.getClass()],
    );

    if (!requiredFlag) {
      return true;
    }

    const request = context.switchToHttp().getRequest();
    const user: User = request.user;

    if (!user) {
      return false;
    }

    const featureFlag = await this.featureFlagRepository.findOne({
      where: {
        accountId: user.accountId,
        name: requiredFlag,
      },
    });

    if (!featureFlag || !featureFlag.enabled) {
      throw new ForbiddenException(
        `The feature "${requiredFlag}" is not enabled for your account.`,
      );
    }

    return true;
  }
}

// ─── Composed Decorator ──────────────────────────────────────────────────────

const AdvancedAnalyticsAccess = () =>
  applyDecorators(
    UseGuards(AuthGuard('jwt'), PremiumSubscriptionGuard, FeatureFlagGuard),
    RequireFeatureFlag('advanced-analytics'),
  );

